¿Que inconveniente presenta la siguiente funcion?```void maze(const Maze &maze, vector< vector< bool > > &visited, Point &currentPoint,size_t currentLength, size_t &currentBestLength) {
	if (currentPoint == maze.exit()) {
		currentBestLength = min(currentBestLength, currentLength);
		return;
	}
	for (auto step : allSteps) {
		Point next = currentPoint.next(step);
		if (maze.is_valid(next) && !visited[next.x()][next.y()] && currentLength <  currentBestLength) {
			visited[next.x()][next.y()] = true;
			maze(maze, visited, next, currentLength + 1, bestLength);
			visited[next.x()][next.y()] = false;
		}
	}
	return;
}```

¿Qué inconveniente presenta la siguiente función?```void maze(const Maze &maze, vector<vector<bool>> &visited, Point &currentPoint, size_t currentLength, size_t &currentBestLength) { 
	if (currentPoint == maze.exit()) { 
		currentBestLength = min(currentBestLength, currentLength); 
		return; 
	} 

	for (auto step : allSteps) { 
		Point next = currentPoint.next(step); 
		if (maze.is_valid(next) && !visited[next.x()][next.y()] && currentLength < currentBestLength) { 
			visited[next.x()][next.y()] = true; 
			maze(maze, visited, next, currentLength + 1, bestLength); 
			visited[next.x()][next.y()] = false; 
		} 
	} 
	return; 
}```

Dado el problema del encaminamiento óptimo (versión simplificada), la siguiente función pretende encontrar la mejor ubicación de las puertas de enlace haciendo uso del almacén M. ¿Es correcta? 

Nota: la función pair<int, double> ogw(...) devuelve, respectivamente, la mejor ubicación de una puerta de enlace entre dos nodos; y el tráfico asociado a esa ubicación de la puerta de enlace)```double met_naive(vector<int>* M, const vector<double>* d, const vector<double>* c, int n, int m) 
{ 
	double best_traffic; 
	int best_gw; 
	if (m == 1) { 
		tie(best_gw, best_traffic) = ogw(d, c, 0, n); 
	} else { 
		best_traffic = numeric_limits<double>::max(); 
		for (int node = m - 1; node < n; node++) { 
			auto [candidate_gw, traffic] = ogw(d, c, node, n); 
			traffic += met_naive(M, d, c, node, m-1); 
			if (traffic < best_traffic) { 
				best_traffic = traffic; 
				best_gw = candidate_gw; 
			} 
		} 
	} 
	M[n] = best_gw; 
	return best_traffic; 
}```
